// List of contact devices
const contacts = [
    'door_front',
    'door_back',
    'door_garage'
    // Add more contact device names here
];

// Store contact list in flow context
flow.set('contactList', contacts);

// Create request messages for each contact
const messages = contacts.map(device => ({
    topic: `zigbee2mqtt/${device}/get`,
    payload: JSON.stringify({}),
    device: device,
    _msgid: node.id + '_' + device
}));

return messages;

// Get contact list from flow context
const contacts = flow.get('contactList') || [
    'door_front',
    'door_back',
    'door_garage'
];

// Extract device name from topic
const topic = msg.topic;
const parts = topic.split('/');
const deviceName = parts[1]; // zigbee2mqtt/<device-name>

// Check if this is a contact device
if (!contacts.includes(deviceName)) {
    return null; // Not a contact device, drop message
}

// Parse payload
let data;
try {
    data = typeof msg.payload === 'string' ? JSON.parse(msg.payload) : msg.payload;
} catch(e) {
    data = { contact: msg.payload };
}

// Extract contact state
// zigbee2mqtt contact sensors typically use:
// - contact: true/false (false = open, true = closed)
// - state.contact: true/false
// - contact_sensor: true/false
const contactState = data.contact !== undefined ? data.contact : 
                    data.state?.contact !== undefined ? data.state.contact :
                    data.contact_sensor !== undefined ? data.contact_sensor :
                    data.state || msg.payload;

// Determine if open or closed
// false or 'open' = door/window is OPEN
// true or 'closed' = door/window is CLOSED
const isOpen = contactState === false || 
               contactState === 'open' || 
               contactState === 'OPEN' ||
               contactState === 0;

const isClosed = contactState === true || 
                 contactState === 'closed' || 
                 contactState === 'CLOSED' ||
                 contactState === 1;

msg.device = deviceName;
msg.contactState = contactState;
msg.isOpen = isOpen;
msg.isClosed = isClosed;
msg.timestamp = new Date().toISOString();
msg.lastUpdate = Date.now();

return msg;

const device = msg.device;
const contacts = flow.get('contactList') || [
    'door_front',
    'door_back',
    'door_garage'
];

// Store current device status in flow context
const status = {
    state: msg.contactState,
    isOpen: msg.isOpen,
    isClosed: msg.isClosed,
    timestamp: msg.timestamp,
    lastUpdate: msg.lastUpdate
};

flow.set(`contact_${device}`, status);

// Get all contacts status
const allStatus = {};
const openContacts = [];
const closedContacts = [];
const unknownContacts = [];

contacts.forEach(contact => {
    const stored = flow.get(`contact_${contact}`);
    if (stored) {
        allStatus[contact] = stored;
        if (stored.isOpen === true) {
            openContacts.push(contact);
        } else if (stored.isClosed === true) {
            closedContacts.push(contact);
        } else {
            unknownContacts.push(contact);
        }
    } else {
        allStatus[contact] = { 
            state: 'unknown', 
            isOpen: null,
            isClosed: null,
            timestamp: null
        };
        unknownContacts.push(contact);
    }
});

// Create summary
msg.allContacts = allStatus;
msg.openContacts = openContacts;
msg.closedContacts = closedContacts;
msg.unknownContacts = unknownContacts;
msg.hasOpenContacts = openContacts.length > 0;
msg.summary = {
    total: contacts.length,
    open: openContacts.length,
    closed: closedContacts.length,
    unknown: unknownContacts.length
};

// Set payload for display
msg.payload = {
    status: msg.hasOpenContacts ? 'ALERT' : 'OK',
    summary: msg.summary,
    openContacts: openContacts,
    timestamp: new Date().toISOString()
};

return msg;

