const openContacts = msg.openContacts || [];
const allStatus = msg.allContacts || {};

// Create detailed alert message
const alertDetails = openContacts.map(name => ({
    device: name,
    status: allStatus[name].state,
    timestamp: allStatus[name].timestamp,
    isOpen: true
}));

const alertMsg = {
    alert: true,
    type: 'door_open',
    severity: 'warning',
    message: `⚠️ ${openContacts.length} contact(s) are OPEN`,
    openContacts: alertDetails,
    summary: msg.summary,
    timestamp: new Date().toISOString()
};

msg.payload = alertMsg;
msg.topic = 'alerts/contacts';
msg.alert = true;

return msg;

msg.payload = {
    status: 'ok',
    message: 'All contacts are closed',
    summary: msg.summary,
    timestamp: new Date().toISOString()
};

return msg;
